import{_ as a,o as t,c as _,j as r,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"鬼下属技艺-血鬼术-上弦之六","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/2.改造与功法/改造/4.综合类/鬼灭之刃-鬼/鬼下属技艺-血鬼术-上弦之六.md","filePath":"4.资源分区/2.改造与功法/改造/4.综合类/鬼灭之刃-鬼/鬼下属技艺-血鬼术-上弦之六.md"}'),o={name:"4.资源分区/2.改造与功法/改造/4.综合类/鬼灭之刃-鬼/鬼下属技艺-血鬼术-上弦之六.md"};function d(b,e,p,l,i,c){return t(),_("div",null,[...e[0]||(e[0]=[r("h1",{id:"鬼下属技艺-血鬼术-上弦之六",tabindex:"-1"},[n("鬼下属技艺-血鬼术-上弦之六 "),r("a",{class:"header-anchor",href:"#鬼下属技艺-血鬼术-上弦之六","aria-label":'Permalink to "鬼下属技艺-血鬼术-上弦之六"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风029特别节愚人版")])])],-1),s('<h1 id="鬼下属技艺-血鬼术-上弦之六-1" tabindex="-1">鬼下属技艺-血鬼术-上弦之六 <a class="header-anchor" href="#鬼下属技艺-血鬼术-上弦之六-1" aria-label="Permalink to &quot;鬼下属技艺-血鬼术-上弦之六&quot;">​</a></h1><p>血鬼术</p><p>上弦之六.妓夫太郎.飞行血镰<br> C+1000<br> “不可原谅！”<br> 通过手中的镰刀发出薄如薄片的血刃对敌人进行斩击，飞行方向由发动者自由决定。<br> 消耗一标准动作，对一个目标进行一次用镰刀的近战攻击，发出多道血刃<br> 该次攻击的射程增加12米，为曲线型攻击。<br> 该次攻击会以本回合目标已经受到过6次攻击计算。</p><p>上弦之六.妓夫太郎.跋弧跳梁<br> C+1000<br> “怎么可能现在还做没意义的攻击？”<br> 通过挥动手中的镰刀发出血之斩击防御大范围的袭击。<br> 手持武器有镰刀的状态下，消耗一个移动动作，进入一个类招架状态，并且在下一次被攻击命中时，可以以反射动作释放跋弧跳梁。<br> 跋弧跳梁是一个类招架行为，在招架的效果以外，挥动的镰刀使攻击无法近身，你在本轮免疫擒抱状态，本次招架视作移出攻击范围，无视1点高速。</p><p>上弦之六.妓夫太郎.圆斩旋.回.飞行血镰<br> C+1000<br> “真有趣啊”<br> 不挥动手臂，将血以螺旋状缠绕在手上进行大范围的斩击<br> 消耗一个标准动作，将镰刀以及手臂变为巨大的血刃风暴中心<br> 仅在上一轮使用过【飞行血镰】后才能使用，<br> 该次攻击攻击触及范围内所有单位，具有【毁灭】效果。<br> 你操控的血刃将会更加猛烈，本次攻击额外具有10高速，在计算破防效果后若是高速仍然有剩余，则等额转变为攻击上的速度加值。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',7)])])}const m=a(o,[["render",d]]);export{f as __pageData,m as default};
